# setup-pwa-gestao-projetos-v4.ps1
# Forca icone proprio e remove icones antigos do Vite/Vercel/cache.
# Marcador: GESTAO_PROJETOS_PWA_V4

$ErrorActionPreference = "Stop"

Write-Host "Aplicando PWA V4 com icone proprio..." -ForegroundColor Cyan

New-Item -ItemType Directory -Force -Path ".\public\icons" | Out-Null

# Remove possiveis icones antigos do Vite
Remove-Item ".\public\vite.svg" -Force -ErrorAction SilentlyContinue
Remove-Item ".\public\favicon.svg" -Force -ErrorAction SilentlyContinue
Remove-Item ".\public\favicon-32x32.png" -Force -ErrorAction SilentlyContinue
Remove-Item ".\public\favicon-16x16.png" -Force -ErrorAction SilentlyContinue

$icons = @{
  "72" = @"

"@
  "96" = @"

"@
  "128" = @"

"@
  "144" = @"

"@
  "152" = @"

"@
  "180" = @"

"@
  "192" = @"

"@
  "384" = @"

"@
  "512" = @"

"@
}

foreach ($size in $icons.Keys) {
  [System.Convert]::FromBase64String($icons[$size]) | Set-Content -Path ".\public\icons\icon-$size.png" -Encoding Byte
}

[System.Convert]::FromBase64String($icons["180"]) | Set-Content -Path ".\public\apple-touch-icon.png" -Encoding Byte
[System.Convert]::FromBase64String($icons["192"]) | Set-Content -Path ".\public\logo192.png" -Encoding Byte
[System.Convert]::FromBase64String($icons["512"]) | Set-Content -Path ".\public\logo512.png" -Encoding Byte
[System.Convert]::FromBase64String($icons["192"]) | Set-Content -Path ".\public\favicon.png" -Encoding Byte

$faviconIco = @"

"@
[System.Convert]::FromBase64String($faviconIco) | Set-Content -Path ".\public\favicon.ico" -Encoding Byte

@'
{
  "id": "/gestao-projetos-pwa-v4",
  "name": "Alexandre Dias | Gestão de Projetos",
  "short_name": "Gestão Projetos",
  "description": "Sistema premium para gestão de projetos de interiores, clientes, prazos e financeiro.",
  "start_url": "/?pwa=v4",
  "scope": "/",
  "display": "standalone",
  "orientation": "portrait-primary",
  "background_color": "#f6efe4",
  "theme_color": "#2d1d17",
  "lang": "pt-BR",
  "categories": ["business", "productivity"],
  "icons": [
    { "src": "/icons/icon-72.png?v=4", "sizes": "72x72", "type": "image/png", "purpose": "any maskable" },
    { "src": "/icons/icon-96.png?v=4", "sizes": "96x96", "type": "image/png", "purpose": "any maskable" },
    { "src": "/icons/icon-128.png?v=4", "sizes": "128x128", "type": "image/png", "purpose": "any maskable" },
    { "src": "/icons/icon-144.png?v=4", "sizes": "144x144", "type": "image/png", "purpose": "any maskable" },
    { "src": "/icons/icon-152.png?v=4", "sizes": "152x152", "type": "image/png", "purpose": "any maskable" },
    { "src": "/icons/icon-192.png?v=4", "sizes": "192x192", "type": "image/png", "purpose": "any maskable" },
    { "src": "/icons/icon-384.png?v=4", "sizes": "384x384", "type": "image/png", "purpose": "any maskable" },
    { "src": "/icons/icon-512.png?v=4", "sizes": "512x512", "type": "image/png", "purpose": "any maskable" }
  ]
}
'@ | Set-Content -Path ".\public\manifest.webmanifest" -Encoding UTF8

@'
// GESTAO_PROJETOS_PWA_V4
const CACHE_NAME = "gestao-projetos-pwa-v4";

self.addEventListener("install", (event) => {
  self.skipWaiting();
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys()
      .then((keys) => Promise.all(keys.map((key) => caches.delete(key))))
      .then(() => self.clients.claim())
  );
});

self.addEventListener("fetch", (event) => {
  if (event.request.method !== "GET") return;

  event.respondWith(
    fetch(event.request).catch(() => caches.match(event.request))
  );
});
'@ | Set-Content -Path ".\public\sw.js" -Encoding UTF8

@'
// GESTAO_PROJETOS_PWA_V4
if ("serviceWorker" in navigator) {
  window.addEventListener("load", async () => {
    try {
      const registrations = await navigator.serviceWorker.getRegistrations();
      await Promise.all(registrations.map((registration) => registration.unregister()));
      await navigator.serviceWorker.register("/sw.js?v=4");
    } catch (error) {
      console.warn("Service Worker não registrado:", error);
    }
  });
}
'@ | Set-Content -Path ".\src\pwa-register.js" -Encoding UTF8

$indexPath = ".\index.html"
$index = Get-Content $indexPath -Raw

# Remove tags antigas de icon/manifest/meta/title
$index = $index -replace '<link rel="icon"[^>]*>\s*', ''
$index = $index -replace '<link rel="shortcut icon"[^>]*>\s*', ''
$index = $index -replace '<link rel="apple-touch-icon"[^>]*>\s*', ''
$index = $index -replace '<link rel="manifest"[^>]*>\s*', ''
$index = $index -replace '<meta name="theme-color"[^>]*>\s*', ''
$index = $index -replace '<meta name="mobile-web-app-capable"[^>]*>\s*', ''
$index = $index -replace '<meta name="apple-mobile-web-app-capable"[^>]*>\s*', ''
$index = $index -replace '<meta name="apple-mobile-web-app-title"[^>]*>\s*', ''
$index = $index -replace '<meta name="application-name"[^>]*>\s*', ''
$index = $index -replace '<title>[\s\S]*?</title>\s*', ''

$headTags = @'
    <!-- GESTAO_PROJETOS_PWA_V4 -->
    <title>Alexandre Dias | Gestão de Projetos</title>
    <link rel="manifest" href="/manifest.webmanifest?v=4" />
    <link rel="icon" href="/favicon.ico?v=4" sizes="any" />
    <link rel="icon" type="image/png" href="/favicon.png?v=4" />
    <link rel="apple-touch-icon" href="/apple-touch-icon.png?v=4" />
    <meta name="theme-color" content="#2d1d17" />
    <meta name="mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-title" content="Gestão Projetos" />
    <meta name="application-name" content="Gestão Projetos" />

'@

# Remove bloco PWA antigo, se existir
$index = $index -replace '<!-- GESTAO_PROJETOS_PWA_V[0-9] -->[\s\S]*?<meta name="application-name" content="[^"]*" />\s*', ''

$index = $index -replace "<head>", "<head>`n$headTags"

if ($index -notmatch "/src/pwa-register.js") {
  $index = $index -replace "</body>", '    <script type="module" src="/src/pwa-register.js"></script>' + "`n  </body>"
}

Set-Content -Path $indexPath -Value $index -Encoding UTF8

Write-Host ""
Write-Host "PWA V4 aplicado." -ForegroundColor Green
Write-Host "Agora faça commit/push e, no celular, limpe dados do site antes de instalar novamente." -ForegroundColor Yellow
